mapper.select:
SELECT t.id, t.id AS taskId, t.schedule_id AS scheduleId, c.name AS courseName, cr.name AS classroomName, th.name AS teacherName, CONCAT('周', cs.weekday, ' 第', cs.start_section_id, '-', cs.end_section_id, '节') AS classTimeText, t.media_type AS mediaType, t.created_at AS createdAt, t.status AS status, cs.student_count AS studentCount, t.attendance_count AS attendanceCount, ar.attendance_rate AS attendanceRate, t.total_score AS totalScore, ar.report_level AS reportLevel, ar.abnormal_flag AS abnormalFlag FROM analysis_task t LEFT JOIN course_schedule cs ON t.schedule_id = cs.id LEFT JOIN course c ON cs.course_id = c.id LEFT JOIN classroom cr ON cs.classroom_id = cr.id LEFT JOIN teacher th ON cs.teacher_id = th.id LEFT JOIN analysis_report ar ON t.id = ar.task_id
AND (c.name LIKE CONCAT('%', #{query.keyword}, '%') OR th.name LIKE CONCAT('%', #{query.keyword}, '%'))
AND DATE(t.created_at) >= #{query.startDate}
AND DATE(t.created_at) <= #{query.endDate}
AND cs.teacher_id = #{currentTeacherId}
ORDER BY t.created_at DESC

SELECT t.id, t.id AS taskId, t.schedule_id AS scheduleId, c.name AS courseName, cr.name AS classroomName, th.name AS teacherName, CONCAT('周', cs.weekday, ' 第', cs.start_section_id, '-', cs.end_section_id, '节') AS classTimeText, t.media_type AS mediaType, t.created_at AS createdAt, t.status AS status, cs.student_count AS studentCount, t.attendance_count AS attendanceCount, ar.attendance_rate AS attendanceRate, t.total_score AS totalScore, ar.report_level AS reportLevel, ar.abnormal_flag AS abnormalFlag FROM analysis_task t LEFT JOIN course_schedule cs ON t.schedule_id = cs.id LEFT JOIN course c ON cs.course_id = c.id LEFT JOIN classroom cr ON cs.classroom_id = cr.id LEFT JOIN teacher th ON cs.teacher_id = th.id LEFT JOIN analysis_report ar ON t.id = ar.task_id WHERE t.id IN
#{id}
AND cs.teacher_id = #{currentTeacherId}
ORDER BY t.created_at DESC

SELECT t.id, c.name AS courseName, cr.name AS classroomName, th.name AS teacherName, t.media_type AS mediaType, t.created_at AS createdAt, t.status AS status, t.attendance_count AS attendanceCount, t.total_score AS totalScore, sf.file_url AS fileUrl, CONCAT(cs.academic_year, '学年 第', cs.semester, '学期 ', CASE cs.weekday WHEN 1 THEN '周一' WHEN 2 THEN '周二' WHEN 3 THEN '周三' WHEN 4 THEN '周四' WHEN 5 THEN '周五' WHEN 6 THEN '周六' WHEN 7 THEN '周日' ELSE '' END, ' 第', cs.start_section_id, '-', cs.end_section_id, '节 ', cs.start_week, '-', cs.end_week, '周') AS classTimeText, cs.student_count AS studentCount, IFNULL(TIMESTAMPDIFF(SECOND, t.start_time, t.finish_time), NULL) AS durationSeconds FROM analysis_task t LEFT JOIN course_schedule cs ON t.schedule_id = cs.id LEFT JOIN course c ON cs.course_id = c.id LEFT JOIN classroom cr ON cs.classroom_id = cr.id LEFT JOIN teacher th ON cs.teacher_id = th.id LEFT JOIN sys_file sf ON t.file_id = sf.id
t.id = #{id}
AND cs.teacher_id = #{currentTeacherId}
